    depths = []
    for group in paren_string.split():
        max_depth = cur = 0
        for ch in group:
            if ch == '(':
                cur += 1
                if cur > max_depth:
                    max_depth = cur
            elif ch == ')':
                cur -= 1
        depths.append(max_depth)
    return depths
